VALUES (163, 1890222389187448832,
        '{\"alertIntervalUnit\":\"分钟\",\"alertIntervalValue\":2,\"alertLevel\":\"4\",\"alertProjectNo\":\"hjf\",\"alertTemplate\":\"[刷单预警2]${FlinkEventDTO.eventAttrMap.bankName}(${FlinkEventDTO.eventAttrMap.bankNo}): 花积分用户(${FlinkEventDTO.targetValue})，最近${RuleInfoDTO.ruleCondGroup.0.windowValue}${RuleInfoDTO.ruleCondGroup.0.windowUnit}内下单金额为${ProcessorDTO.eventValueGroup.orderAmount}，超过${RuleInfoDTO.ruleCondGroup.0.threshold}元；或最近${RuleInfoDTO.ruleCondGroup.1.windowValue}${RuleInfoDTO.ruleCondGroup.1.windowUnit}内下单数量为${ProcessorDTO.eventValueGroup.orderCount}，超过${RuleInfoDTO.ruleCondGroup.1.threshold}次；触发预警的商品为：${FlinkEventDTO.eventAttrMap.productName}(${FlinkEventDTO.eventAttrMap.productId})。请您及时查看原因！\",\"channel\":\"hjf\",\"modelCode\":1889596060557512704,\"modelGroovy\":\"package com.liboshuai.slr.engine.biz.processor.impl\\n\\nimport com.liboshuai.slr.engine.api.dto.*\\nimport com.liboshuai.slr.engine.api.enums.RuleCondCombOpEnum\\nimport com.liboshuai.slr.engine.api.enums.RuleCondTypeEnum\\nimport com.liboshuai.slr.engine.api.enums.TimeUnitEnum\\nimport com.liboshuai.slr.engine.api.utils.TimeUtil\\nimport com.liboshuai.slr.engine.biz.framework.state.ProcessorOneStateDesc\\nimport com.liboshuai.slr.engine.biz.processor.Processor\\nimport com.liboshuai.slr.engine.biz.util.CollectionUtil\\nimport com.liboshuai.slr.engine.biz.util.RedisUtil\\nimport com.liboshuai.slr.engine.biz.util.RuleEventAttrCompUtil\\nimport com.liboshuai.slr.framework.common.constants.RedisKeyConstants\\nimport com.liboshuai.slr.framework.common.enums.CommonStatusEnum\\nimport com.liboshuai.slr.framework.common.util.date.LocalDateTimeUtils\\nimport com.liboshuai.slr.framework.common.util.json.JsonUtils\\nimport com.liboshuai.slr.framework.common.util.string.TemplateUtil\\nimport org.apache.flink.api.common.functions.RuntimeContext\\nimport org.apache.flink.api.common.state.*\\nimport org.apache.flink.api.java.tuple.Tuple2\\nimport org.apache.flink.util.Collector\\nimport org.apache.flink.util.StringUtils\\nimport org.slf4j.Logger\\nimport org.slf4j.LoggerFactory \\n\\npublic class ProcessorOne implements Processor {\\n\\n    private static final Logger log = LoggerFactory.getLogger(ProcessorOne.class);\\n\\n    /**\\n     * 规则信息\\n     */\\n    private RuleInfoDTO ruleInfoDTO;\\n    /**\\n     * - key: f0为事件字段，f1为时间戳\\n     * - value: f0为eventValue累加值，f1为最新的事件数据\\n     */\\n    private MapState<Tuple2<String, Long>, Tuple2<Long, FlinkEventDTO>> smallMapState;\\n    /**\\n     * 记录对于事件条件是否初始化过\\n     * - key: eventField\\n     * - value: 任意值\\n     * （注意不要使用ListState，它查找指定元素的性能很差）\\n     */\\n    private MapState<String, Boolean> smallInitMapState;\\n    /**\\n     * 记录是否使用了状态\\n     */\\n    private ValueState<Boolean> hasValueState;\\n    /**\\n     * 最新的事件数据\\n     */\\n    private ValueState<FlinkEventDTO> lastEventState;\\n    /**\\n     * 规则最近一次触发预警时间\\n     */\\n    private ValueState<Long> lastWarningTimeState;\\n    /**\\n     * 最新更新的事件阈值\\n     * - key: eventField\\n     * - value: 最新更新eventThreshold\\n     */\\n    private MapState<String, Long> latestEventThresholdMapState;\\n    /**\\n     * key: f0为eventField，f1为时间戳\\n     * value: eventValue累加值\\n     */\\n    private MapState<Tuple2<String, Long>, Long> bigMapState;\\n\\n    // 上一个同规则的运算机残留状态（仅用于测试打印日志使用）\\n    // private MapState<Tuple2<String, Long>, Tuple2<Long, Long>> oldBigMapState;\\n\\n    /**\\n     * 初始化方法，用于在运行时上下文中注册各种状态\\n     *\\n     * @param runtimeContext 运行时上下文，用于访问状态和其它运行时设施\\n     * @param ruleInfoDTO    规则信息数据传输对象，包含规则特定的元数据\\n     */\\n    @Override\\n    public void init(RuntimeContext runtimeContext, KeyedStateStore keyedStateStore, RuleInfoDTO ruleInfoDTO) {\\n        this.ruleInfoDTO = ruleInfoDTO;\\n        Long ruleCode = ruleInfoDTO.getRuleCode();\\n        Long ruleVersion = ruleInfoDTO.getRuleVersion();\\n\\n        boolean isRuntimeContextPresent = Objects.nonNull(runtimeContext);\\n\\n        smallMapState = getMapState(isRuntimeContextPresent, runtimeContext, keyedStateStore, ProcessorOneStateDesc.getSmallMapStateDesc(ruleCode, ruleVersion));\\n        smallInitMapState = getMapState(isRuntimeContextPresent, runtimeContext, keyedStateStore, ProcessorOneStateDesc.getSmallInitMapStateDesc(ruleCode, ruleVersion));\\n        hasValueState = getValueState(isRuntimeContextPresent, runtimeContext, keyedStateStore, ProcessorOneStateDesc.getHasValueState(ruleCode, ruleVersion));\\n        lastEventState = getValueState(isRuntimeContextPresent, runtimeContext, keyedStateStore, ProcessorOneStateDesc.getLastEventStateDesc(ruleCode, ruleVersion));\\n        lastWarningTimeState = getValueState(isRuntimeContextPresent, runtimeContext, keyedStateStore, ProcessorOneStateDesc.getLastWarningTimeStateDesc(ruleCode, ruleVersion));\\n        latestEventThresholdMapState = getMapState(isRuntimeContextPresent, runtimeContext, keyedStateStore, ProcessorOneStateDesc.getLatestEventThresholdMapStateDesc(ruleCode, ruleVersion));\\n        bigMapState = getMapState(isRuntimeContextPresent, runtimeContext, keyedStateStore, ProcessorOneStateDesc.getGigMapStateDesc(ruleCode, ruleVersion));\\n\\n        // 上一个同规则的运算机残留状态（仅用于测试打印日志使用）\\n//         oldBigMapState = getMapState(isRuntimeContextPresent, runtimeContext, keyedStateStore, ProcessorOneStateDesc.getGigMapStateDesc(ruleCode, ruleVersion - 1));\\n    }\\n\\n    private <K, V> MapState<K, V> getMapState(boolean isRuntimeContextPresent, RuntimeContext runtimeContext, KeyedStateStore keyedStateStore, MapStateDescriptor<K, V> descriptor) {\\n        return isRuntimeContextPresent ? runtimeContext.getMapState(descriptor) : keyedStateStore.getMapState(descriptor);\\n    }\\n\\n    private <T> ValueState<T> getValueState(boolean isRuntimeContextPresent, RuntimeContext runtimeContext, KeyedStateStore keyedStateStore, ValueStateDescriptor<T> descriptor) {\\n        return isRuntimeContextPresent ? runtimeContext.getState(descriptor) : keyedStateStore.getState(descriptor);\\n    }\\n\\n    /**\\n     * 处理元素事件，根据给定的规则信息和Kafka事件进行处理\\n     *\\n     * @param processTimestamp 时间戳，用于处理的时间参考\\n     * @param flinkEventDTO         Kafka事件数据传输对象，包含事件的详细信息\\n     * @param out                   用于输出处理结果的收集器\\n     * @throws Exception 如果处理过程中遇到任何错误，则抛出异常\\n     */\\n    @Override\\n    public void processElement(String currentKey, long processTimestamp, FlinkEventDTO flinkEventDTO,\\n                               Collector<FlinkResultDTO> out) throws Exception {\\n        if (Objects.isNull(ruleInfoDTO)) {\\n            log.warn(\\\"因规则信息为空，故跳过此次计算！当前事件数据：{}\\\", flinkEventDTO);\\n            return;\\n        }\\n        if (!Objects.equals(ruleInfoDTO.getRuleStatus(), CommonStatusEnum.ONLINE.getCode())\\n                && !Objects.equals(ruleInfoDTO.getRuleStatus(), CommonStatusEnum.OFFLINE_PENDING.getCode())) {\\n            log.warn(\\\"因规则[{}]的状态不为\'已上线\'或\'下线待审核\'，故跳过此次计算！当前事件数据：{}\\\", ruleInfoDTO.getRuleCode(), flinkEventDTO);\\n            return;\\n        }\\n        // 事件与规则渠道匹配不上，则直接跳过\\n        if (!Objects.equals(flinkEventDTO.getChannel(), ruleInfoDTO.getChannel())) {\\n            return;\\n        }\\n        // 事件与规则目标匹配不上，则直接跳过\\n        if (!Objects.equals(flinkEventDTO.getTargetField(), ruleInfoDTO.getTargetField())) {\\n            return;\\n        }\\n        // 获取规则条件\\n        List<RuleCondDTO> condGroupList = ruleInfoDTO.getRuleCondGroup();\\n        if (condGroupList == null || condGroupList.isEmpty()) {\\n            log.warn(\\\"因规则[{}]的条件组为空，故跳过此次计算！当前事件数据：{}\\\", ruleInfoDTO.getRuleCode(), flinkEventDTO);\\n            return;\\n        }\\n        // 此模型仅支持条件为周期类型的规则\\n        for (RuleCondDTO condGroupDTO : condGroupList) {\\n            String type = condGroupDTO.getCondType();\\n            if (!Objects.equals(type, RuleCondTypeEnum.PERIODIC.getCode())) {\\n                log.warn(\\\"因规则[{}]的条件类型不为周期类型，故跳过此次计算！当前事件数据：{}\\\", ruleInfoDTO.getRuleCode(), flinkEventDTO);\\n                return;\\n            }\\n        }\\n        // 计算规则条件值\\n        processRuleCondValue(processTimestamp, ruleInfoDTO, flinkEventDTO, out);\\n    }\\n\\n    /**\\n     * 处理规则条件值\\n     * 该方法主要用于处理一组规则条件DTO，通过与Kafka事件DTO进行匹配来更新状态值\\n     * 如果规则条件跨越历史时间段，则需要从Redis中获取历史事件值，并进行初始化\\n     *\\n     * @param processTimestamp 时间戳，用于非跨历史时间段的事件匹配\\n     * @param flinkEventDTO         Kafka事件DTO\\n     */\\n    private void processRuleCondValue(long processTimestamp, RuleInfoDTO ruleInfoDTO,\\n                                      FlinkEventDTO flinkEventDTO, Collector<FlinkResultDTO> out) throws Exception {\\n        List<RuleCondDTO> ruleCondGroup = ruleInfoDTO.getRuleCondGroup();\\n        for (RuleCondDTO ruleCondDTO : ruleCondGroup) {\\n            // 事件与规则中的事件编号匹配不上，则直接跳过\\n            if (!Objects.equals(flinkEventDTO.getEventField(), ruleCondDTO.getEventField())) {\\n                // 事件编号匹配不上，则直接跳过\\n                continue;\\n            }\\n            // 进行事件属性匹配\\n            List<RuleEventAttrValueDTO> ruleEventAttrValueGroup = ruleCondDTO.getRuleEventAttrValueGroup();\\n            boolean eventAttributeMatchResult = matchEventAttribute(ruleEventAttrValueGroup, flinkEventDTO);\\n            if (!eventAttributeMatchResult) {\\n                // 事件属性匹配不上，则直接跳过\\n                continue;\\n            }\\n            // 规则状态历史的记录数据\\n            Boolean hasState = hasValueState.value();\\n            if (Objects.isNull(hasState) || !hasState) {\\n                StateDTO stateDTO = StateDTO.builder()\\n                        .ruleCode(ruleInfoDTO.getRuleCode())\\n                        .ruleVersion(ruleInfoDTO.getRuleVersion())\\n                        .channel(ruleInfoDTO.getChannel())\\n                        .targetField(flinkEventDTO.getTargetField())\\n                        .targetValue(flinkEventDTO.getTargetValue())\\n                        .build();\\n                out.collect(FlinkResultDTO.builder().stateDTO(stateDTO).build());\\n                hasValueState.update(true);\\n            }\\n            // 状态值防空\\n            Tuple2<Long, FlinkEventDTO> eventValueAndEventDateTuple2 = smallMapState.get(Tuple2.of(flinkEventDTO.getEventField(), processTimestamp));\\n            if (Objects.isNull(eventValueAndEventDateTuple2)) {\\n                smallMapState.put(Tuple2.of(flinkEventDTO.getEventField(), processTimestamp), Tuple2.of(0L, flinkEventDTO));\\n            }\\n            // 规则事件值计算\\n            if (ruleCondDTO.getCrossHistory()) { //跨历史时间段\\n                String crossHistoryTimeline = ruleCondDTO.getCrossHistoryTimeline();\\n                // 因为跨历史时间段的规则条件需要处理历史缓存的数据，而历史缓存的数据可能过多，\\n                // 所以需要根据历史截止点进行过滤，仅需要大于历史截止点的数据\\n                if (flinkEventDTO.getEventTime()\\n                        <= LocalDateTimeUtils.convertString2Timestamp(crossHistoryTimeline)) {\\n                    continue;\\n                }\\n                // 因为跨历史时间段的规则条件需要从redis中获取doris中历史事件值，\\n                // 所以检查当前值是否已经通过redis初始化后，防止重复初始化\\n                if (!smallInitMapState.contains(flinkEventDTO.getEventField())) {\\n                    // 如果为跨历史时间段的，且还没有初始化，则需要从redis中获取初始值\\n                    // （注意：Groovy字符串拼接的方式很麻烦，故使用StringBuilder）\\n                    String redisKey = buildRedisKey(ruleCondDTO);\\n                    String redisHashKey = buildRedisHashKey(flinkEventDTO);\\n                    // 注意：因为上面获取历史缓存数据时，使用的是 <= 所以 redis 存储值时查询 doris 要包含历史截至时间点\\n                    String initValue = RedisUtil.hget(redisKey, redisHashKey);\\n                    RedisUtil.hdel(redisKey, redisHashKey);\\n                    if (StringUtils.isNullOrWhitespaceOnly(initValue)) {\\n                        log.warn(\\\"因规则[{}]的redis初始值为空，故跳过此次计算！redisKey: {}, redisHashKey: {}, 当前事件数据：{}\\\", ruleInfoDTO.getRuleCode(), redisKey, redisHashKey, flinkEventDTO);\\n                        return;\\n                    }\\n                    smallMapState.put(Tuple2.of(flinkEventDTO.getEventField(), processTimestamp), Tuple2.of(Long.parseLong(initValue), flinkEventDTO));\\n                    smallInitMapState.put(flinkEventDTO.getEventField(), true);\\n                }\\n                // 从redis初始化值后，正常处理数据\\n                addEventValue(processTimestamp, flinkEventDTO);\\n            } else { // 非跨历史时间段\\n                // 对于非跨历史时间段，只处理当前一条数据，不需要处理历史缓存数据\\n                if (flinkEventDTO.getEventTime() != processTimestamp) {\\n                    continue;\\n                }\\n                addEventValue(processTimestamp, flinkEventDTO);\\n            }\\n        }\\n    }\\n\\n    private void addEventValue(long processTimestamp, FlinkEventDTO flinkEventDTO) throws Exception {\\n        Tuple2<Long, FlinkEventDTO> eventValueAndEventDateTuple2 = smallMapState.get(Tuple2.of(flinkEventDTO.getEventField(), processTimestamp));\\n        Long currentValue = eventValueAndEventDateTuple2.f0;\\n        Long newValue = currentValue + Long.parseLong(flinkEventDTO.getEventValue());\\n        smallMapState.put(Tuple2.of(flinkEventDTO.getEventField(), processTimestamp), Tuple2.of(newValue, flinkEventDTO));\\n    }\\n\\n\\n    /**\\n     * 构建Redis的哈希键\\n     */\\n    private String buildRedisHashKey(FlinkEventDTO flinkEventDTO) {\\n        String targetField = flinkEventDTO.getTargetField();\\n        String targetValue = flinkEventDTO.getTargetValue();\\n        return targetField +\\n                RedisKeyConstants.REDIS_KEY_SPLIT +\\n                targetValue;\\n    }\\n\\n    /**\\n     * 构建Redis的key\\n     */\\n    private String buildRedisKey(RuleCondDTO ruleCondDTO) {\\n        return RedisKeyConstants.DORIS_EVENT_HISTORY_VALUE +\\n                RedisKeyConstants.REDIS_KEY_SPLIT +\\n                ruleCondDTO.getRuleCode() +\\n                RedisKeyConstants.REDIS_KEY_SPLIT +\\n                ruleCondDTO.getEventField();\\n    }\\n\\n    /**\\n     * 匹配规则事件属性与Kafka事件属性是否符合\\n     * 此方法的目的是为了验证给定的Kafka事件是否满足规则事件中定义的所有属性条件\\n     * 它通过比较规则事件属性和Kafka事件属性来确定两者是否匹配\\n     *\\n     * @param flinkEventDTO Kafka事件DTO，包含Kafka事件的详细信息，包括事件属性\\n     * @return boolean 如果Kafka事件属性与规则事件属性完全匹配，则返回true；否则返回false\\n     */\\n    private boolean matchEventAttribute(List<RuleEventAttrValueDTO> ruleEventAttrValueGroup, FlinkEventDTO flinkEventDTO) {\\n        if (CollectionUtil.isEmptyOrContainsNulls(ruleEventAttrValueGroup)) {\\n            // 规则中不包含事件属性相关的配置，则表明不需要进行事件属性匹配，直接跳过即可\\n            return true;\\n        }\\n        // 逐一便利验证事件属性\\n        for (RuleEventAttrValueDTO ruleEventAttrValueDTO : ruleEventAttrValueGroup) {\\n            String attrValue = ruleEventAttrValueDTO.getAttrValue();\\n            if (StringUtils.isNullOrWhitespaceOnly(attrValue)) {\\n                // 规则中不包含事件属性值相关的配置，则表明不需要进行事件属性值匹配，直接跳过即可\\n                continue;\\n            }\\n            String attrField = ruleEventAttrValueDTO.getAttrField();\\n            Map<String, String> kafkaEventAttrMap = flinkEventDTO.getEventAttrMap();\\n            if (Objects.isNull(kafkaEventAttrMap) || kafkaEventAttrMap.isEmpty()) {\\n                // 规则包含事件属性配置，但是kafka数据事件属性map为空，故直接判定为不符合规则要求\\n                log.warn(\\\"规则包含事件属性配置，但是kafka数据事件属性map为空，故直接判定为不符合规则要求！\\\" +\\n                        \\\"规则事件属性信息:{}, 当前事件信息:{}\\\", ruleEventAttrValueDTO, flinkEventDTO);\\n                return false;\\n            }\\n            if (!kafkaEventAttrMap.containsKey(attrField)) {\\n                // kafka事件属性不包含规则中事件属性，则表明不符合匹配\\n                log.warn(\\\"kafka数据事件属性map并不包含规则配置的事件属性Field，故直接判定为不符合规则要求！\\\" +\\n                        \\\"规则事件属性信息:{}, 当前事件信息:{}\\\", ruleEventAttrValueDTO, flinkEventDTO);\\n                return false;\\n            }\\n            String kafkaEventAttributeValue = kafkaEventAttrMap.get(attrField);\\n            if (Objects.isNull(kafkaEventAttributeValue)) {\\n                // kafka事件中对于规则中事件属性值为空，则表明不符合匹配\\n                return false;\\n            }\\n            // 比较kafka中属性值与规则中属性值\\n            boolean isMatch = RuleEventAttrCompUtil.compareValues(ruleEventAttrValueDTO, flinkEventDTO);\\n            if (!isMatch) {\\n                // kafka事件属性值与规则事件属性值不相等，则表明不符合匹配\\n                return false;\\n            }\\n        }\\n        // 所有事件属性都匹配，则表明符合匹配\\n        return true;\\n    }\\n\\n    /**\\n     * 定时器触发时执行的方法\\n     *\\n     * @param processTimestamp 处理时间戳\\n     * @param out       输出收集器，用于收集和输出预警信息\\n     * @throws Exception 可能抛出的异常\\n     */\\n    @Override\\n    public boolean onTimer(String currentKey, long processTimestamp, Collector<FlinkResultDTO> out) throws Exception {\\n        if (Objects.isNull(ruleInfoDTO)) {\\n            log.warn(\\\"因规则信息为空，故跳过此次计算！\\\");\\n            return true;\\n        }\\n        // 获取规则条件\\n        List<RuleCondDTO> ruleCondGroup = ruleInfoDTO.getRuleCondGroup();\\n        if (ruleCondGroup == null || ruleCondGroup.isEmpty()) {\\n            log.warn(\\\"因规则[{}]的条件组为空，故跳过此次计算！\\\", ruleInfoDTO.getRuleCode());\\n            return false;\\n        }\\n        // 将规则条件根据事件编号存储到map中，方便后续操作\\n        Map<String, RuleCondDTO> ruleConditionMapByEventField = new HashMap<>();\\n        for (RuleCondDTO ruleCondDTO : ruleCondGroup) {\\n            ruleConditionMapByEventField.put(ruleCondDTO.getEventField(), ruleCondDTO);\\n        }\\n        // 将小时间窗口（步长窗口）中的数据累加到大时间窗口（整体窗口）中，并返回最新（时间戳最大）的事件数据。\\n        aggregateSmallMapToBigMap(processTimestamp);\\n        // 清理窗口大小之外的数据\\n        cleanupWindowData(processTimestamp, ruleConditionMapByEventField);\\n        // 处理bigMapState\\n        Tuple2<Boolean, ProcessorDTO> processBigMapResult = processBigMap(ruleConditionMapByEventField, ruleInfoDTO.getRuleCondCombOp());\\n        // 根据规则中事件条件表达式组合判断事件结果 与预警频率 判断否是触发预警\\n        if (lastWarningTimeState.value() == null) {\\n            lastWarningTimeState.update(0L);\\n        }\\n        // 获取预警间隔时间，单位为毫秒\\n        Long alertInterval = getAlertInterval(ruleInfoDTO);\\n        // 检查是否需要发送预警\\n        boolean shouldAlert = processBigMapResult.f0 &&\\n                (alertInterval == null || (processTimestamp - lastWarningTimeState.value() >= alertInterval));\\n        if (shouldAlert) {\\n            // 更新最后预警时间\\n            lastWarningTimeState.update(processTimestamp);\\n            // 发送预警信息\\n            AlertDTO alertDTO = buildAlert(processTimestamp, ruleInfoDTO, lastEventState.value(), processBigMapResult);\\n            log.info(\\\"最终推送的预警信息内容：{}, 当前Key: {}\\\", JsonUtils.toJsonString(alertDTO), currentKey);\\n            FlinkResultDTO flinkResultDTO = FlinkResultDTO.builder().alertDTO(alertDTO).build();\\n            out.collect(flinkResultDTO);\\n        }\\n        return hasActiveEvents();\\n    }\\n\\n    private void logSmallMapState(Long ruleCode, String currentKey) throws Exception {\\n        Map<Tuple2<String, Long>, Tuple2<Long, FlinkEventDTO>> smallMap = new HashMap<>();\\n        for (Map.Entry<Tuple2<String, Long>, Tuple2<Long, FlinkEventDTO>> entry : smallMapState.entries()) {\\n            smallMap.put(entry.getKey(), entry.getValue());\\n        }\\n        log.debug(\\\"smallMap：{}, ruleCode:{}, currentKey：{}\\\", JsonUtils.toJsonString(smallMap), ruleCode, currentKey);\\n    }\\n\\n    private void logBigMapState(Long ruleCode, String currentKey) throws Exception {\\n        Map<Tuple2<String, Long>, Long> bigMap = new HashMap<>();\\n        for (Map.Entry<Tuple2<String, Long>, Long> entry : bigMapState.entries()) {\\n            bigMap.put(entry.getKey(), entry.getValue());\\n        }\\n        log.debug(\\\"bigMap：{}, ruleCode:{}, currentKey：{}\\\", JsonUtils.toJsonString(bigMap), ruleCode, currentKey);\\n    }\\n\\n//    private void logOldState(Long ruleCode, String currentKey) throws Exception {\\n//        Map<Tuple2<String, Long>, Tuple2<Long, Long>> bigMap = new HashMap<>();\\n//        for (Map.Entry<Tuple2<String, Long>, Tuple2<Long, Long>> entry : oldBigMapState.entries()) {\\n//            bigMap.put(entry.getKey(), entry.getValue());\\n//        }\\n//        log.debug(\\\"残留旧状态，ruleCode:{}, currentKey：{}, bigMap：{}\\\", ruleCode, currentKey, bigMap);\\n//    }\\n\\n    /**\\n     * 构建预警信息的方法，提取重复逻辑\\n     */\\n    private AlertDTO buildAlert(long processTimestamp, RuleInfoDTO ruleInfoDTO, FlinkEventDTO latestFlinkEventDTO, Tuple2<Boolean, ProcessorDTO> processBigMapResult) {\\n        String finalWarnMessage = TemplateUtil.replacePlaceholders(\\n                ruleInfoDTO.getAlertTemplate(),\\n                ruleInfoDTO,\\n                latestFlinkEventDTO,\\n                processBigMapResult.f1\\n        );\\n        return AlertDTO.builder()\\n                .channel(ruleInfoDTO.getChannel())\\n                .ruleCode(ruleInfoDTO.getRuleCode())\\n                .message(finalWarnMessage)\\n                .time(LocalDateTimeUtils.convertTimestamp2String(processTimestamp))\\n                .targetField(ruleInfoDTO.getTargetField())\\n                .targetValue(latestFlinkEventDTO.getTargetValue())\\n                .eventValueGroup(processBigMapResult.f1.getEventValueGroup())\\n                .build();\\n    }\\n\\n    private Long getAlertInterval(RuleInfoDTO ruleInfoDTO) {\\n        Long alertIntervalValue = ruleInfoDTO.getAlertIntervalValue();\\n        String alertIntervalUnit = ruleInfoDTO.getAlertIntervalUnit();\\n        if (Objects.isNull(alertIntervalValue) || Objects.isNull(alertIntervalUnit)) {\\n            return null;\\n        }\\n        return TimeUtil.toMillis(alertIntervalValue, TimeUnitEnum.fromEnUnit(alertIntervalUnit));\\n    }\\n\\n    /**\\n     * 检查是否存在活跃的事件\\n     * 该方法用于遍历一个大的状态映射，以确定其中是否包含活跃的Kafka事件\\n     *\\n     * @return boolean - 如果存在活跃的事件，则返回true；否则返回false\\n     */\\n    private boolean hasActiveEvents() throws Exception {\\n        return bigMapState.entries().iterator().hasNext();\\n    }\\n\\n    /**\\n     * 处理大映射表中的数据以确定是否满足规则条件\\n     * 此方法主要负责遍历大映射表状态，计算每个事件字段的累加值，判断是否满足规则条件，并返回相关的处理结果\\n     *\\n     * @param ruleConditionMapByEventField 按事件字段分类的规则条件映射表\\n     * @param ruleCondCombOp               规则条件的组合操作符，用于确定如何组合多个规则条件的结果\\n     * @return 返回一个Tuple2对象，包含事件结果、处理器DTO\\n     * @throws Exception 如果处理过程中发生错误，则抛出异常\\n     */\\n    private Tuple2<Boolean, ProcessorDTO> processBigMap(Map<String, RuleCondDTO> ruleConditionMapByEventField,\\n                                                        String ruleCondCombOp) throws Exception {\\n        // 获取事件与之判断结果\\n        Map<String, Boolean> eventFieldAndWarnResult = new HashMap<>();\\n        // 获取事件字段与值之和\\n        Map<String, Long> eventFiledAndValueSumMap = new HashMap<>();\\n        // 遍历 MapState 的所有条目\\n        for (Map.Entry<Tuple2<String, Long>, Long> entry : bigMapState.entries()) {\\n            Tuple2<String, Long> key = entry.getKey(); // 获取键，包含 eventField 和关联的时间戳值\\n            Long eventValue = entry.getValue(); // 获取事件累加值\\n            String eventField = key.f0; // Tuple2 的第一个元素作为事件字段\\n            // 使用 merge 方法高效地累加值\\n            eventFiledAndValueSumMap.merge(eventField, eventValue, Long::sum);\\n        }\\n        // 确保所有规则条件中的事件字段都被包含，如果不存在则设置为 0L\\n        Set<String> eventFieldSet = ruleConditionMapByEventField.keySet();\\n        for (String eventField : eventFieldSet) {\\n            eventFiledAndValueSumMap.putIfAbsent(eventField, 0L);\\n        }\\n        // 判断是否触发规则事件阈值\\n        for (String eventField : eventFieldSet) {\\n            Long eventValueSum = eventFiledAndValueSumMap.get(eventField);\\n            RuleCondDTO ruleCondDTO = ruleConditionMapByEventField.get(eventField);\\n            // 获取事件的阈值\\n            Long eventThreshold = getEventThreshold(eventField, ruleCondDTO);\\n            eventFieldAndWarnResult.put(eventField, eventValueSum > eventThreshold);\\n        }\\n        boolean eventResult = evaluateEventResults(eventFieldAndWarnResult, ruleCondCombOp);\\n        // 构建运算机的DTO对象\\n        ProcessorDTO processorDTO = ProcessorDTO.builder()\\n                .eventValueGroup(eventFiledAndValueSumMap)\\n                .build();\\n        return Tuple2.of(eventResult, processorDTO);\\n    }\\n\\n    /**\\n     * 获取事件的阈值\\n     * 此方法用于计算和获取给定规则条件下的事件阈值如果设置了阈值缩放因子，则使用之；\\n     * 否则直接返回规则条件中的阈值\\n     *\\n     * @param eventField  事件字段，用于查找可能已经存在的阈值\\n     * @param ruleCondDTO 规则条件对象，包含阈值和阈值缩放因子\\n     * @return 计算后的事件阈值\\n     * @throws Exception 如果计算过程中发生错误，则抛出异常\\n     */\\n    private Long getEventThreshold(String eventField, RuleCondDTO ruleCondDTO) throws Exception {\\n        Long eventThreshold = ruleCondDTO.getThreshold();\\n        Long thresholdScaleFactor = ruleCondDTO.getThresholdScaleFactor();\\n        if (Objects.nonNull(thresholdScaleFactor)) {\\n            Long latestThreshold = latestEventThresholdMapState.get(eventField);\\n            // FIXME: 逻辑错误，应该对应条件预警触发后，才更新\\n            if (Objects.nonNull(latestThreshold)) {\\n                eventThreshold = latestThreshold * thresholdScaleFactor;\\n            }\\n            latestEventThresholdMapState.put(eventField, eventThreshold);\\n        }\\n        return eventThreshold;\\n    }\\n\\n\\n    /**\\n     * 将小时间窗口（步长窗口）中的数据累加到大时间窗口（整体窗口）中，并更新最新（时间戳最大）的事件数据。\\n     */\\n    private void aggregateSmallMapToBigMap(long processTimestamp) throws Exception {\\n        // 遍历 smallMapState 的所有条目\\n        Long timestampMax = 0L;\\n        for (Map.Entry<Tuple2<String, Long>, Tuple2<Long, FlinkEventDTO>> smallMapEntry : smallMapState.entries()) {\\n            Tuple2<String, Long> eventFieldAndTimeTuple2 = smallMapEntry.getKey();\\n            Tuple2<Long, FlinkEventDTO> eventValueAndEventDataTuple2 = smallMapEntry.getValue();\\n            // 创建新的 Tuple2 作为 bigMapState 的键\\n            Tuple2<String, Long> tupleKey = Tuple2.of(eventFieldAndTimeTuple2.f0, processTimestamp);\\n            // 将 (eventField, processTimestamp) 作为键，eventValue 作为值，存入 bigMapState\\n            Long oldValue = bigMapState.get(tupleKey);\\n            if (Objects.isNull(oldValue)) {\\n                oldValue = 0L;\\n            }\\n            bigMapState.put(tupleKey, oldValue + eventValueAndEventDataTuple2.f0);\\n            // 更新最新的事件数据\\n            Long eventTime = eventFieldAndTimeTuple2.f1;\\n            if (eventTime > timestampMax) {\\n                timestampMax = eventTime;\\n                lastEventState.update(eventValueAndEventDataTuple2.f1);\\n            }\\n        }\\n        // 当前窗口步长的数据已经添加到窗口中了，清空当前key状态\\n        smallMapState.clear();\\n    }\\n\\n    /**\\n     * 清理窗口大小之外的数据\\n     */\\n    private void cleanupWindowData(long processTimestamp, Map<String, RuleCondDTO> ruleConditionMapByEventField) throws Exception {\\n        // 提前计算每个 eventField 的 windowSize 和 windowThresholdTime\\n        Map<String, Long> eventFieldToThresholdTime = new HashMap<>();\\n\\n        for (Map.Entry<String, RuleCondDTO> entry : ruleConditionMapByEventField.entrySet()) {\\n            String eventField = entry.getKey();\\n            RuleCondDTO ruleCondDTO = entry.getValue();\\n            long windowSize = TimeUtil.toMillis(ruleCondDTO.getWindowValue(),\\n                    TimeUnitEnum.fromEnUnit(ruleCondDTO.getWindowUnit()));\\n            long windowThresholdTime = processTimestamp - windowSize;\\n            eventFieldToThresholdTime.put(eventField, windowThresholdTime);\\n        }\\n\\n        // 遍历 bigMapState 的所有条目\\n        Iterator<Map.Entry<Tuple2<String, Long>, Long>> iterator = bigMapState.entries().iterator();\\n        while (iterator.hasNext()) {\\n            Map.Entry<Tuple2<String, Long>, Long> stateEntry = iterator.next();\\n            Tuple2<String, Long> eventFieldAndTimeTuple2 = stateEntry.getKey();\\n            String eventField = eventFieldAndTimeTuple2.f0;\\n            Long eventTime = eventFieldAndTimeTuple2.f1;\\n\\n            RuleCondDTO ruleCondDTO = ruleConditionMapByEventField.get(eventField);\\n            if (Objects.isNull(ruleCondDTO)) {\\n                log.warn(\\\"清理窗口大小之外的数据时，存在规则条件中不存在的 eventField: {}\\\", eventField);\\n                continue;\\n            }\\n\\n            Long windowThresholdTime = eventFieldToThresholdTime.get(eventField);\\n            if (eventTime <= windowThresholdTime) {\\n                // 删除过期的条目\\n                iterator.remove();\\n            }\\n        }\\n    }\\n\\n    /**\\n     * 评估事件结果，根据给定的条件操作符返回最终结果。\\n     *\\n     * @param eventFieldAndWarnResult 包含事件代码及其对应的警告结果的映射\\n     * @param conditionOperator       条件操作符，支持 AND 和 OR\\n     * @return 根据条件操作符计算后的最终结果（true 或 false）\\n     */\\n    private boolean evaluateEventResults(Map<String, Boolean> eventFieldAndWarnResult, String conditionOperator) {\\n        // 检查输入是否为 null 或为空\\n        if (eventFieldAndWarnResult == null || eventFieldAndWarnResult.isEmpty()) {\\n            return false;\\n        }\\n\\n        // 如果只有一个元素，直接返回该元素的值\\n        if (eventFieldAndWarnResult.size() == 1) {\\n            return eventFieldAndWarnResult.values().iterator().next();\\n        }\\n\\n        // 确定操作符类型\\n        RuleCondCombOpEnum opEnum = RuleCondCombOpEnum.fromCode(conditionOperator);\\n\\n        // 初始化结果，根据操作符类型\\n        boolean result;\\n        if (opEnum == RuleCondCombOpEnum.AND) {\\n            result = true; // 对于 AND，初始值为 true\\n            for (Boolean eventResult : eventFieldAndWarnResult.values()) {\\n                if (!eventResult) {\\n                    return false; // 任何一个 false 都返回 false\\n                }\\n            }\\n        } else if (opEnum == RuleCondCombOpEnum.OR) {\\n            result = false; // 对于 OR，初始值为 false\\n            for (Boolean eventResult : eventFieldAndWarnResult.values()) {\\n                if (eventResult) {\\n                    return true; // 任何一个 true 都返回 true\\n                }\\n            }\\n        } else {\\n            log.warn(\\\"因规则[{}]的条件组合操作符非法，故跳过此次计算！\\\", ruleInfoDTO.getRuleCode());\\n            return false;\\n        }\\n\\n        return result;\\n    }\\n}\\n\",\"ruleCode\":1890222389187448832,\"ruleCondCombOp\":\"OR\",\"ruleCondGroup\":[{\"condCode\":\"1890222389187448832_hjf_userId_orderAmount\",\"condType\":\"CYCLE\",\"crossHistory\":false,\"eventCode\":\"hjf_userId_orderAmount\",\"eventField\":\"orderAmount\",\"eventName\":\"花积分下单数量\",\"ruleCode\":1890222389187448832,\"threshold\":100,\"windowUnit\":\"分钟\",\"windowValue\":5},{\"condCode\":\"1890222389187448832_hjf_userId_orderCount\",\"condType\":\"CYCLE\",\"crossHistory\":false,\"eventCode\":\"hjf_userId_orderCount\",\"eventField\":\"orderCount\",\"eventName\":\"花积分下单数量\",\"ruleCode\":1890222389187448832,\"threshold\":10,\"windowUnit\":\"分钟\",\"windowValue\":5}],\"ruleDesc\":\"花积分刷单规则2\",\"ruleName\":\"花积分刷单2\",\"ruleStatus\":\"ONLINE\",\"ruleVersion\":3,\"targetCode\":\"hjf_userId\",\"targetField\":\"userId\",\"targetName\":\"花积分用户id\"}',
        'system', NULL, '2025-02-18 18:59:10', NULL);

-- ----------------------------
-- Table structure for slr_rule_model
-- ----------------------------
DROP TABLE IF EXISTS `slr_rule_model`;
CREATE TABLE `slr_rule_model`
(
    `id`          bigint UNSIGNED                                       NOT NULL AUTO_INCREMENT COMMENT '自增主键ID',
    `model_code`  bigint UNSIGNED                                       NULL DEFAULT NULL COMMENT '模型编号',
    `model_name`  varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '模型名称',
    `model_desc`  varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '模型描述',
    `groovy`      text CHARACTER SET utf8mb4 COLLATE utf8mb4_bin        NULL COMMENT '运算机groovy代码',
    `creator`     varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '创建用户',
    `updater`     varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '更新用户',
    `create_time` datetime                                              NULL DEFAULT NULL COMMENT '创建时间',
    `update_time` datetime                                              NULL DEFAULT NULL COMMENT '创建时间',
    PRIMARY KEY (`id`) USING BTREE,
    UNIQUE INDEX `uk_model_code` (`model_code` ASC) USING BTREE
) ENGINE = InnoDB
  AUTO_INCREMENT = 3
  CHARACTER SET = utf8mb4
  COLLATE = utf8mb4_bin COMMENT = '风控规则模型表'
  ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of slr_rule_model
-- ----------------------------
INSERT INTO `slr_rule_model`
VALUES (2, 1889596060557512704, '模型运算机一', '支持多周期条件、事件属性过滤的规则模型',
        'package com.liboshuai.slr.engine.biz.processor.impl\n\nimport com.liboshuai.slr.engine.api.dto.*\nimport com.liboshuai.slr.engine.api.enums.RuleCondCombOpEnum\nimport com.liboshuai.slr.engine.api.enums.RuleCondTypeEnum\nimport com.liboshuai.slr.engine.api.enums.TimeUnitEnum\nimport com.liboshuai.slr.engine.api.utils.TimeUtil\nimport com.liboshuai.slr.engine.biz.framework.state.ProcessorOneStateDesc\nimport com.liboshuai.slr.engine.biz.processor.Processor\nimport com.liboshuai.slr.engine.biz.util.CollectionUtil\nimport com.liboshuai.slr.engine.biz.util.RedisUtil\nimport com.liboshuai.slr.engine.biz.util.RuleEventAttrCompUtil\nimport com.liboshuai.slr.framework.common.constants.RedisKeyConstants\nimport com.liboshuai.slr.framework.common.enums.CommonStatusEnum\nimport com.liboshuai.slr.framework.common.util.date.LocalDateTimeUtils\nimport com.liboshuai.slr.framework.common.util.json.JsonUtils\nimport com.liboshuai.slr.framework.common.util.string.TemplateUtil\nimport org.apache.flink.api.common.functions.RuntimeContext\nimport org.apache.flink.api.common.state.*\nimport org.apache.flink.api.java.tuple.Tuple2\nimport org.apache.flink.util.Collector\nimport org.apache.flink.util.StringUtils\nimport org.slf4j.Logger\nimport org.slf4j.LoggerFactory \n\npublic class ProcessorOne implements Processor {\n\n    private static final Logger log = LoggerFactory.getLogger(ProcessorOne.class);\n\n    /**\n     * 规则信息\n     */\n    private RuleInfoDTO ruleInfoDTO;\n    /**\n     * - key: f0为事件字段，f1为时间戳\n     * - value: f0为eventValue累加值，f1为最新的事件数据\n     */\n    private MapState<Tuple2<String, Long>, Tuple2<Long, FlinkEventDTO>> smallMapState;\n    /**\n     * 记录对于事件条件是否初始化过\n     * - key: eventField\n     * - value: 任意值\n     * （注意不要使用ListState，它查找指定元素的性能很差）\n     */\n    private MapState<String, Boolean> smallInitMapState;\n    /**\n     * 记录是否使用了状态\n     */\n    private ValueState<Boolean> hasValueState;\n    /**\n     * 最新的事件数据\n     */\n    private ValueState<FlinkEventDTO> lastEventState;\n    /**\n     * 规则最近一次触发预警时间\n     */\n    private ValueState<Long> lastWarningTimeState;\n    /**\n     * 最新更新的事件阈值\n     * - key: eventField\n     * - value: 最新更新eventThreshold\n     */\n    private MapState<String, Long> latestEventThresholdMapState;\n    /**\n     * key: f0为eventField，f1为时间戳\n     * value: eventValue累加值\n     */\n    private MapState<Tuple2<String, Long>, Long> bigMapState;\n\n    // 上一个同规则的运算机残留状态（仅用于测试打印日志使用）\n    // private MapState<Tuple2<String, Long>, Tuple2<Long, Long>> oldBigMapState;\n\n    /**\n     * 初始化方法，用于在运行时上下文中注册各种状态\n     *\n     * @param runtimeContext 运行时上下文，用于访问状态和其它运行时设施\n     * @param ruleInfoDTO    规则信息数据传输对象，包含规则特定的元数据\n     */\n    @Override\n    public void init(RuntimeContext runtimeContext, KeyedStateStore keyedStateStore, RuleInfoDTO ruleInfoDTO) {\n        this.ruleInfoDTO = ruleInfoDTO;\n        Long ruleCode = ruleInfoDTO.getRuleCode();\n        Long ruleVersion = ruleInfoDTO.getRuleVersion();\n\n        boolean isRuntimeContextPresent = Objects.nonNull(runtimeContext);\n\n        smallMapState = getMapState(isRuntimeContextPresent, runtimeContext, keyedStateStore, ProcessorOneStateDesc.getSmallMapStateDesc(ruleCode, ruleVersion));\n        smallInitMapState = getMapState(isRuntimeContextPresent, runtimeContext, keyedStateStore, ProcessorOneStateDesc.getSmallInitMapStateDesc(ruleCode, ruleVersion));\n        hasValueState = getValueState(isRuntimeContextPresent, runtimeContext, keyedStateStore, ProcessorOneStateDesc.getHasValueState(ruleCode, ruleVersion));\n        lastEventState = getValueState(isRuntimeContextPresent, runtimeContext, keyedStateStore, ProcessorOneStateDesc.getLastEventStateDesc(ruleCode, ruleVersion));\n        lastWarningTimeState = getValueState(isRuntimeContextPresent, runtimeContext, keyedStateStore, ProcessorOneStateDesc.getLastWarningTimeStateDesc(ruleCode, ruleVersion));\n        latestEventThresholdMapState = getMapState(isRuntimeContextPresent, runtimeContext, keyedStateStore, ProcessorOneStateDesc.getLatestEventThresholdMapStateDesc(ruleCode, ruleVersion));\n        bigMapState = getMapState(isRuntimeContextPresent, runtimeContext, keyedStateStore, ProcessorOneStateDesc.getGigMapStateDesc(ruleCode, ruleVersion));\n\n        // 上一个同规则的运算机残留状态（仅用于测试打印日志使用）\n//         oldBigMapState = getMapState(isRuntimeContextPresent, runtimeContext, keyedStateStore, ProcessorOneStateDesc.getGigMapStateDesc(ruleCode, ruleVersion - 1));\n    }\n\n    private <K, V> MapState<K, V> getMapState(boolean isRuntimeContextPresent, RuntimeContext runtimeContext, KeyedStateStore keyedStateStore, MapStateDescriptor<K, V> descriptor) {\n        return isRuntimeContextPresent ? runtimeContext.getMapState(descriptor) : keyedStateStore.getMapState(descriptor);\n    }\n\n    private <T> ValueState<T> getValueState(boolean isRuntimeContextPresent, RuntimeContext runtimeContext, KeyedStateStore keyedStateStore, ValueStateDescriptor<T> descriptor) {\n        return isRuntimeContextPresent ? runtimeContext.getState(descriptor) : keyedStateStore.getState(descriptor);\n    }\n\n    /**\n     * 处理元素事件，根据给定的规则信息和Kafka事件进行处理\n     *\n     * @param processTimestamp 时间戳，用于处理的时间参考\n     * @param flinkEventDTO         Kafka事件数据传输对象，包含事件的详细信息\n     * @param out                   用于输出处理结果的收集器\n     * @throws Exception 如果处理过程中遇到任何错误，则抛出异常\n     */\n    @Override\n    public void processElement(String currentKey, long processTimestamp, FlinkEventDTO flinkEventDTO,\n                               Collector<FlinkResultDTO> out) throws Exception {\n        if (Objects.isNull(ruleInfoDTO)) {\n            log.warn(\"因规则信息为空，故跳过此次计算！当前事件数据：{}\", flinkEventDTO);\n            return;\n        }\n        if (!Objects.equals(ruleInfoDTO.getRuleStatus(), CommonStatusEnum.ONLINE.getCode())\n                && !Objects.equals(ruleInfoDTO.getRuleStatus(), CommonStatusEnum.OFFLINE_PENDING.getCode())) {\n            log.warn(\"因规则[{}]的状态不为\'已上线\'或\'下线待审核\'，故跳过此次计算！当前事件数据：{}\", ruleInfoDTO.getRuleCode(), flinkEventDTO);\n            return;\n        }\n        // 事件与规则渠道匹配不上，则直接跳过\n        if (!Objects.equals(flinkEventDTO.getChannel(), ruleInfoDTO.getChannel())) {\n            return;\n        }\n        // 事件与规则目标匹配不上，则直接跳过\n        if (!Objects.equals(flinkEventDTO.getTargetField(), ruleInfoDTO.getTargetField())) {\n            return;\n        }\n        // 获取规则条件\n        List<RuleCondDTO> condGroupList = ruleInfoDTO.getRuleCondGroup();\n        if (condGroupList == null || condGroupList.isEmpty()) {\n            log.warn(\"因规则[{}]的条件组为空，故跳过此次计算！当前事件数据：{}\", ruleInfoDTO.getRuleCode(), flinkEventDTO);\n            return;\n        }\n        // 此模型仅支持条件为周期类型的规则\n        for (RuleCondDTO condGroupDTO : condGroupList) {\n            String type = condGroupDTO.getCondType();\n            if (!Objects.equals(type, RuleCondTypeEnum.PERIODIC.getCode())) {\n                log.warn(\"因规则[{}]的条件类型不为周期类型，故跳过此次计算！当前事件数据：{}\", ruleInfoDTO.getRuleCode(), flinkEventDTO);\n                return;\n            }\n        }\n        // 计算规则条件值\n        processRuleCondValue(processTimestamp, ruleInfoDTO, flinkEventDTO, out);\n    }\n\n    /**\n     * 处理规则条件值\n     * 该方法主要用于处理一组规则条件DTO，通过与Kafka事件DTO进行匹配来更新状态值\n     * 如果规则条件跨越历史时间段，则需要从Redis中获取历史事件值，并进行初始化\n     *\n     * @param processTimestamp 时间戳，用于非跨历史时间段的事件匹配\n     * @param flinkEventDTO         Kafka事件DTO\n     */\n    private void processRuleCondValue(long processTimestamp, RuleInfoDTO ruleInfoDTO,\n                                      FlinkEventDTO flinkEventDTO, Collector<FlinkResultDTO> out) throws Exception {\n        List<RuleCondDTO> ruleCondGroup = ruleInfoDTO.getRuleCondGroup();\n        for (RuleCondDTO ruleCondDTO : ruleCondGroup) {\n            // 事件与规则中的事件编号匹配不上，则直接跳过\n            if (!Objects.equals(flinkEventDTO.getEventField(), ruleCondDTO.getEventField())) {\n                // 事件编号匹配不上，则直接跳过\n                continue;\n            }\n            // 进行事件属性匹配\n            List<RuleEventAttrValueDTO> ruleEventAttrValueGroup = ruleCondDTO.getRuleEventAttrValueGroup();\n            boolean eventAttributeMatchResult = matchEventAttribute(ruleEventAttrValueGroup, flinkEventDTO);\n            if (!eventAttributeMatchResult) {\n                // 事件属性匹配不上，则直接跳过\n                continue;\n            }\n            // 规则状态历史的记录数据\n            Boolean hasState = hasValueState.value();\n            if (Objects.isNull(hasState) || !hasState) {\n                StateDTO stateDTO = StateDTO.builder()\n                        .ruleCode(ruleInfoDTO.getRuleCode())\n                        .ruleVersion(ruleInfoDTO.getRuleVersion())\n                        .channel(ruleInfoDTO.getChannel())\n                        .targetField(flinkEventDTO.getTargetField())\n                        .targetValue(flinkEventDTO.getTargetValue())\n                        .build();\n                out.collect(FlinkResultDTO.builder().stateDTO(stateDTO).build());\n                hasValueState.update(true);\n            }\n            // 状态值防空\n            Tuple2<Long, FlinkEventDTO> eventValueAndEventDateTuple2 = smallMapState.get(Tuple2.of(flinkEventDTO.getEventField(), processTimestamp));\n            if (Objects.isNull(eventValueAndEventDateTuple2)) {\n                smallMapState.put(Tuple2.of(flinkEventDTO.getEventField(), processTimestamp), Tuple2.of(0L, flinkEventDTO));\n            }\n            // 规则事件值计算\n            if (ruleCondDTO.getCrossHistory()) { //跨历史时间段\n                String crossHistoryTimeline = ruleCondDTO.getCrossHistoryTimeline();\n                // 因为跨历史时间段的规则条件需要处理历史缓存的数据，而历史缓存的数据可能过多，\n                // 所以需要根据历史截止点进行过滤，仅需要大于历史截止点的数据\n                if (flinkEventDTO.getEventTime()\n                        <= LocalDateTimeUtils.convertString2Timestamp(crossHistoryTimeline)) {\n                    continue;\n                }\n                // 因为跨历史时间段的规则条件需要从redis中获取doris中历史事件值，\n                // 所以检查当前值是否已经通过redis初始化后，防止重复初始化\n                if (!smallInitMapState.contains(flinkEventDTO.getEventField())) {\n                    // 如果为跨历史时间段的，且还没有初始化，则需要从redis中获取初始值\n                    // （注意：Groovy字符串拼接的方式很麻烦，故使用StringBuilder）\n                    String redisKey = buildRedisKey(ruleCondDTO);\n                    String redisHashKey = buildRedisHashKey(flinkEventDTO);\n                    // 注意：因为上面获取历史缓存数据时，使用的是 <= 所以 redis 存储值时查询 doris 要包含历史截至时间点\n                    String initValue = RedisUtil.hget(redisKey, redisHashKey);\n                    RedisUtil.hdel(redisKey, redisHashKey);\n                    if (StringUtils.isNullOrWhitespaceOnly(initValue)) {\n                        log.warn(\"因规则[{}]的redis初始值为空，故跳过此次计算！redisKey: {}, redisHashKey: {}, 当前事件数据：{}\", ruleInfoDTO.getRuleCode(), redisKey, redisHashKey, flinkEventDTO);\n                        return;\n                    }\n                    smallMapState.put(Tuple2.of(flinkEventDTO.getEventField(), processTimestamp), Tuple2.of(Long.parseLong(initValue), flinkEventDTO));\n                    smallInitMapState.put(flinkEventDTO.getEventField(), true);\n                }\n                // 从redis初始化值后，正常处理数据\n                addEventValue(processTimestamp, flinkEventDTO);\n            } else { // 非跨历史时间段\n                // 对于非跨历史时间段，只处理当前一条数据，不需要处理历史缓存数据\n                if (flinkEventDTO.getEventTime() != processTimestamp) {\n                    continue;\n                }\n                addEventValue(processTimestamp, flinkEventDTO);\n            }\n        }\n    }\n\n    private void addEventValue(long processTimestamp, FlinkEventDTO flinkEventDTO) throws Exception {\n        Tuple2<Long, FlinkEventDTO> eventValueAndEventDateTuple2 = smallMapState.get(Tuple2.of(flinkEventDTO.getEventField(), processTimestamp));\n        Long currentValue = eventValueAndEventDateTuple2.f0;\n        Long newValue = currentValue + Long.parseLong(flinkEventDTO.getEventValue());\n        smallMapState.put(Tuple2.of(flinkEventDTO.getEventField(), processTimestamp), Tuple2.of(newValue, flinkEventDTO));\n    }\n\n\n    /**\n     * 构建Redis的哈希键\n     */\n    private String buildRedisHashKey(FlinkEventDTO flinkEventDTO) {\n        String targetField = flinkEventDTO.getTargetField();\n        String targetValue = flinkEventDTO.getTargetValue();\n        return targetField +\n                RedisKeyConstants.REDIS_KEY_SPLIT +\n                targetValue;\n    }\n\n    /**\n     * 构建Redis的key\n     */\n    private String buildRedisKey(RuleCondDTO ruleCondDTO) {\n        return RedisKeyConstants.DORIS_EVENT_HISTORY_VALUE +\n                RedisKeyConstants.REDIS_KEY_SPLIT +\n                ruleCondDTO.getRuleCode() +\n                RedisKeyConstants.REDIS_KEY_SPLIT +\n                ruleCondDTO.getEventField();\n    }\n\n    /**\n     * 匹配规则事件属性与Kafka事件属性是否符合\n     * 此方法的目的是为了验证给定的Kafka事件是否满足规则事件中定义的所有属性条件\n     * 它通过比较规则事件属性和Kafka事件属性来确定两者是否匹配\n     *\n     * @param flinkEventDTO Kafka事件DTO，包含Kafka事件的详细信息，包括事件属性\n     * @return boolean 如果Kafka事件属性与规则事件属性完全匹配，则返回true；否则返回false\n     */\n    private boolean matchEventAttribute(List<RuleEventAttrValueDTO> ruleEventAttrValueGroup, FlinkEventDTO flinkEventDTO) {\n        if (CollectionUtil.isEmptyOrContainsNulls(ruleEventAttrValueGroup)) {\n            // 规则中不包含事件属性相关的配置，则表明不需要进行事件属性匹配，直接跳过即可\n            return true;\n        }\n        // 逐一便利验证事件属性\n        for (RuleEventAttrValueDTO ruleEventAttrValueDTO : ruleEventAttrValueGroup) {\n            String attrValue = ruleEventAttrValueDTO.getAttrValue();\n            if (StringUtils.isNullOrWhitespaceOnly(attrValue)) {\n                // 规则中不包含事件属性值相关的配置，则表明不需要进行事件属性值匹配，直接跳过即可\n                continue;\n            }\n            String attrField = ruleEventAttrValueDTO.getAttrField();\n            Map<String, String> kafkaEventAttrMap = flinkEventDTO.getEventAttrMap();\n            if (Objects.isNull(kafkaEventAttrMap) || kafkaEventAttrMap.isEmpty()) {\n                // 规则包含事件属性配置，但是kafka数据事件属性map为空，故直接判定为不符合规则要求\n                log.warn(\"规则包含事件属性配置，但是kafka数据事件属性map为空，故直接判定为不符合规则要求！\" +\n                        \"规则事件属性信息:{}, 当前事件信息:{}\", ruleEventAttrValueDTO, flinkEventDTO);\n                return false;\n            }\n            if (!kafkaEventAttrMap.containsKey(attrField)) {\n                // kafka事件属性不包含规则中事件属性，则表明不符合匹配\n                log.warn(\"kafka数据事件属性map并不包含规则配置的事件属性Field，故直接判定为不符合规则要求！\" +\n                        \"规则事件属性信息:{}, 当前事件信息:{}\", ruleEventAttrValueDTO, flinkEventDTO);\n                return false;\n            }\n            String kafkaEventAttributeValue = kafkaEventAttrMap.get(attrField);\n            if (Objects.isNull(kafkaEventAttributeValue)) {\n                // kafka事件中对于规则中事件属性值为空，则表明不符合匹配\n                return false;\n            }\n            // 比较kafka中属性值与规则中属性值\n            boolean isMatch = RuleEventAttrCompUtil.compareValues(ruleEventAttrValueDTO, flinkEventDTO);\n            if (!isMatch) {\n                // kafka事件属性值与规则事件属性值不相等，则表明不符合匹配\n                return false;\n            }\n        }\n        // 所有事件属性都匹配，则表明符合匹配\n        return true;\n    }\n\n    /**\n     * 定时器触发时执行的方法\n     *\n     * @param processTimestamp 处理时间戳\n     * @param out       输出收集器，用于收集和输出预警信息\n     * @throws Exception 可能抛出的异常\n     */\n    @Override\n    public boolean onTimer(String currentKey, long processTimestamp, Collector<FlinkResultDTO> out) throws Exception {\n        if (Objects.isNull(ruleInfoDTO)) {\n            log.warn(\"因规则信息为空，故跳过此次计算！\");\n            return true;\n        }\n        // 获取规则条件\n        List<RuleCondDTO> ruleCondGroup = ruleInfoDTO.getRuleCondGroup();\n        if (ruleCondGroup == null || ruleCondGroup.isEmpty()) {\n            log.warn(\"因规则[{}]的条件组为空，故跳过此次计算！\", ruleInfoDTO.getRuleCode());\n            return false;\n        }\n        // 将规则条件根据事件编号存储到map中，方便后续操作\n        Map<String, RuleCondDTO> ruleConditionMapByEventField = new HashMap<>();\n        for (RuleCondDTO ruleCondDTO : ruleCondGroup) {\n            ruleConditionMapByEventField.put(ruleCondDTO.getEventField(), ruleCondDTO);\n        }\n        // 将小时间窗口（步长窗口）中的数据累加到大时间窗口（整体窗口）中，并返回最新（时间戳最大）的事件数据。\n        aggregateSmallMapToBigMap(processTimestamp);\n        // 清理窗口大小之外的数据\n        cleanupWindowData(processTimestamp, ruleConditionMapByEventField);\n        // 处理bigMapState\n        Tuple2<Boolean, ProcessorDTO> processBigMapResult = processBigMap(ruleConditionMapByEventField, ruleInfoDTO.getRuleCondCombOp());\n        // 根据规则中事件条件表达式组合判断事件结果 与预警频率 判断否是触发预警\n        if (lastWarningTimeState.value() == null) {\n            lastWarningTimeState.update(0L);\n        }\n        // 获取预警间隔时间，单位为毫秒\n        Long alertInterval = getAlertInterval(ruleInfoDTO);\n        // 检查是否需要发送预警\n        boolean shouldAlert = processBigMapResult.f0 &&\n                (alertInterval == null || (processTimestamp - lastWarningTimeState.value() >= alertInterval));\n        if (shouldAlert) {\n            // 更新最后预警时间\n            lastWarningTimeState.update(processTimestamp);\n            // 发送预警信息\n            AlertDTO alertDTO = buildAlert(processTimestamp, ruleInfoDTO, lastEventState.value(), processBigMapResult);\n            log.info(\"最终推送的预警信息内容：{}, 当前Key: {}\", JsonUtils.toJsonString(alertDTO), currentKey);\n            FlinkResultDTO flinkResultDTO = FlinkResultDTO.builder().alertDTO(alertDTO).build();\n            out.collect(flinkResultDTO);\n        }\n        return hasActiveEvents();\n    }\n\n    private void logSmallMapState(Long ruleCode, String currentKey) throws Exception {\n        Map<Tuple2<String, Long>, Tuple2<Long, FlinkEventDTO>> smallMap = new HashMap<>();\n        for (Map.Entry<Tuple2<String, Long>, Tuple2<Long, FlinkEventDTO>> entry : smallMapState.entries()) {\n            smallMap.put(entry.getKey(), entry.getValue());\n        }\n        log.debug(\"smallMap：{}, ruleCode:{}, currentKey：{}\", JsonUtils.toJsonString(smallMap), ruleCode, currentKey);\n    }\n\n    private void logBigMapState(Long ruleCode, String currentKey) throws Exception {\n        Map<Tuple2<String, Long>, Long> bigMap = new HashMap<>();\n        for (Map.Entry<Tuple2<String, Long>, Long> entry : bigMapState.entries()) {\n            bigMap.put(entry.getKey(), entry.getValue());\n        }\n        log.debug(\"bigMap：{}, ruleCode:{}, currentKey：{}\", JsonUtils.toJsonString(bigMap), ruleCode, currentKey);\n    }\n\n//    private void logOldState(Long ruleCode, String currentKey) throws Exception {\n//        Map<Tuple2<String, Long>, Tuple2<Long, Long>> bigMap = new HashMap<>();\n//        for (Map.Entry<Tuple2<String, Long>, Tuple2<Long, Long>> entry : oldBigMapState.entries()) {\n//            bigMap.put(entry.getKey(), entry.getValue());\n//        }\n//        log.debug(\"残留旧状态，ruleCode:{}, currentKey：{}, bigMap：{}\", ruleCode, currentKey, bigMap);\n//    }\n\n    /**\n     * 构建预警信息的方法，提取重复逻辑\n     */\n    private AlertDTO buildAlert(long processTimestamp, RuleInfoDTO ruleInfoDTO, FlinkEventDTO latestFlinkEventDTO, Tuple2<Boolean, ProcessorDTO> processBigMapResult) {\n        String finalWarnMessage = TemplateUtil.replacePlaceholders(\n                ruleInfoDTO.getAlertTemplate(),\n                ruleInfoDTO,\n                latestFlinkEventDTO,\n                processBigMapResult.f1\n        );\n        return AlertDTO.builder()\n                .channel(ruleInfoDTO.getChannel())\n                .ruleCode(ruleInfoDTO.getRuleCode())\n                .message(finalWarnMessage)\n                .time(LocalDateTimeUtils.convertTimestamp2String(processTimestamp))\n                .targetField(ruleInfoDTO.getTargetField())\n                .targetValue(latestFlinkEventDTO.getTargetValue())\n                .eventValueGroup(processBigMapResult.f1.getEventValueGroup())\n                .build();\n    }\n\n    private Long getAlertInterval(RuleInfoDTO ruleInfoDTO) {\n        Long alertIntervalValue = ruleInfoDTO.getAlertIntervalValue();\n        String alertIntervalUnit = ruleInfoDTO.getAlertIntervalUnit();\n        if (Objects.isNull(alertIntervalValue) || Objects.isNull(alertIntervalUnit)) {\n            return null;\n        }\n        return TimeUtil.toMillis(alertIntervalValue, TimeUnitEnum.fromEnUnit(alertIntervalUnit));\n    }\n\n    /**\n     * 检查是否存在活跃的事件\n     * 该方法用于遍历一个大的状态映射，以确定其中是否包含活跃的Kafka事件\n     *\n     * @return boolean - 如果存在活跃的事件，则返回true；否则返回false\n     */\n    private boolean hasActiveEvents() throws Exception {\n        return bigMapState.entries().iterator().hasNext();\n    }\n\n    /**\n     * 处理大映射表中的数据以确定是否满足规则条件\n     * 此方法主要负责遍历大映射表状态，计算每个事件字段的累加值，判断是否满足规则条件，并返回相关的处理结果\n     *\n     * @param ruleConditionMapByEventField 按事件字段分类的规则条件映射表\n     * @param ruleCondCombOp               规则条件的组合操作符，用于确定如何组合多个规则条件的结果\n     * @return 返回一个Tuple2对象，包含事件结果、处理器DTO\n     * @throws Exception 如果处理过程中发生错误，则抛出异常\n     */\n    private Tuple2<Boolean, ProcessorDTO> processBigMap(Map<String, RuleCondDTO> ruleConditionMapByEventField,\n                                                        String ruleCondCombOp) throws Exception {\n        // 获取事件与之判断结果\n        Map<String, Boolean> eventFieldAndWarnResult = new HashMap<>();\n        // 获取事件字段与值之和\n        Map<String, Long> eventFiledAndValueSumMap = new HashMap<>();\n        // 遍历 MapState 的所有条目\n        for (Map.Entry<Tuple2<String, Long>, Long> entry : bigMapState.entries()) {\n            Tuple2<String, Long> key = entry.getKey(); // 获取键，包含 eventField 和关联的时间戳值\n            Long eventValue = entry.getValue(); // 获取事件累加值\n            String eventField = key.f0; // Tuple2 的第一个元素作为事件字段\n            // 使用 merge 方法高效地累加值\n            eventFiledAndValueSumMap.merge(eventField, eventValue, Long::sum);\n        }\n        // 确保所有规则条件中的事件字段都被包含，如果不存在则设置为 0L\n        Set<String> eventFieldSet = ruleConditionMapByEventField.keySet();\n        for (String eventField : eventFieldSet) {\n            eventFiledAndValueSumMap.putIfAbsent(eventField, 0L);\n        }\n        // 判断是否触发规则事件阈值\n        for (String eventField : eventFieldSet) {\n            Long eventValueSum = eventFiledAndValueSumMap.get(eventField);\n            RuleCondDTO ruleCondDTO = ruleConditionMapByEventField.get(eventField);\n            // 获取事件的阈值\n            Long eventThreshold = getEventThreshold(eventField, ruleCondDTO);\n            eventFieldAndWarnResult.put(eventField, eventValueSum > eventThreshold);\n        }\n        boolean eventResult = evaluateEventResults(eventFieldAndWarnResult, ruleCondCombOp);\n        // 构建运算机的DTO对象\n        ProcessorDTO processorDTO = ProcessorDTO.builder()\n                .eventValueGroup(eventFiledAndValueSumMap)\n                .build();\n        return Tuple2.of(eventResult, processorDTO);\n    }\n\n    /**\n     * 获取事件的阈值\n     * 此方法用于计算和获取给定规则条件下的事件阈值如果设置了阈值缩放因子，则使用之；\n     * 否则直接返回规则条件中的阈值\n     *\n     * @param eventField  事件字段，用于查找可能已经存在的阈值\n     * @param ruleCondDTO 规则条件对象，包含阈值和阈值缩放因子\n     * @return 计算后的事件阈值\n     * @throws Exception 如果计算过程中发生错误，则抛出异常\n     */\n    private Long getEventThreshold(String eventField, RuleCondDTO ruleCondDTO) throws Exception {\n        Long eventThreshold = ruleCondDTO.getThreshold();\n        Long thresholdScaleFactor = ruleCondDTO.getThresholdScaleFactor();\n        if (Objects.nonNull(thresholdScaleFactor)) {\n            Long latestThreshold = latestEventThresholdMapState.get(eventField);\n            // FIXME: 逻辑错误，应该对应条件预警触发后，才更新\n            if (Objects.nonNull(latestThreshold)) {\n                eventThreshold = latestThreshold * thresholdScaleFactor;\n            }\n            latestEventThresholdMapState.put(eventField, eventThreshold);\n        }\n        return eventThreshold;\n    }\n\n\n    /**\n     * 将小时间窗口（步长窗口）中的数据累加到大时间窗口（整体窗口）中，并更新最新（时间戳最大）的事件数据。\n     */\n    private void aggregateSmallMapToBigMap(long processTimestamp) throws Exception {\n        // 遍历 smallMapState 的所有条目\n        Long timestampMax = 0L;\n        for (Map.Entry<Tuple2<String, Long>, Tuple2<Long, FlinkEventDTO>> smallMapEntry : smallMapState.entries()) {\n            Tuple2<String, Long> eventFieldAndTimeTuple2 = smallMapEntry.getKey();\n            Tuple2<Long, FlinkEventDTO> eventValueAndEventDataTuple2 = smallMapEntry.getValue();\n            // 创建新的 Tuple2 作为 bigMapState 的键\n            Tuple2<String, Long> tupleKey = Tuple2.of(eventFieldAndTimeTuple2.f0, processTimestamp);\n            // 将 (eventField, processTimestamp) 作为键，eventValue 作为值，存入 bigMapState\n            Long oldValue = bigMapState.get(tupleKey);\n            if (Objects.isNull(oldValue)) {\n                oldValue = 0L;\n            }\n            bigMapState.put(tupleKey, oldValue + eventValueAndEventDataTuple2.f0);\n            // 更新最新的事件数据\n            Long eventTime = eventFieldAndTimeTuple2.f1;\n            if (eventTime > timestampMax) {\n                timestampMax = eventTime;\n                lastEventState.update(eventValueAndEventDataTuple2.f1);\n            }\n        }\n        // 当前窗口步长的数据已经添加到窗口中了，清空当前key状态\n        smallMapState.clear();\n    }\n\n    /**\n     * 清理窗口大小之外的数据\n     */\n    private void cleanupWindowData(long processTimestamp, Map<String, RuleCondDTO> ruleConditionMapByEventField) throws Exception {\n        // 提前计算每个 eventField 的 windowSize 和 windowThresholdTime\n        Map<String, Long> eventFieldToThresholdTime = new HashMap<>();\n\n        for (Map.Entry<String, RuleCondDTO> entry : ruleConditionMapByEventField.entrySet()) {\n            String eventField = entry.getKey();\n            RuleCondDTO ruleCondDTO = entry.getValue();\n            long windowSize = TimeUtil.toMillis(ruleCondDTO.getWindowValue(),\n                    TimeUnitEnum.fromEnUnit(ruleCondDTO.getWindowUnit()));\n            long windowThresholdTime = processTimestamp - windowSize;\n            eventFieldToThresholdTime.put(eventField, windowThresholdTime);\n        }\n\n        // 遍历 bigMapState 的所有条目\n        Iterator<Map.Entry<Tuple2<String, Long>, Long>> iterator = bigMapState.entries().iterator();\n        while (iterator.hasNext()) {\n            Map.Entry<Tuple2<String, Long>, Long> stateEntry = iterator.next();\n            Tuple2<String, Long> eventFieldAndTimeTuple2 = stateEntry.getKey();\n            String eventField = eventFieldAndTimeTuple2.f0;\n            Long eventTime = eventFieldAndTimeTuple2.f1;\n\n            RuleCondDTO ruleCondDTO = ruleConditionMapByEventField.get(eventField);\n            if (Objects.isNull(ruleCondDTO)) {\n                log.warn(\"清理窗口大小之外的数据时，存在规则条件中不存在的 eventField: {}\", eventField);\n                continue;\n            }\n\n            Long windowThresholdTime = eventFieldToThresholdTime.get(eventField);\n            if (eventTime <= windowThresholdTime) {\n                // 删除过期的条目\n                iterator.remove();\n            }\n        }\n    }\n\n    /**\n     * 评估事件结果，根据给定的条件操作符返回最终结果。\n     *\n     * @param eventFieldAndWarnResult 包含事件代码及其对应的警告结果的映射\n     * @param conditionOperator       条件操作符，支持 AND 和 OR\n     * @return 根据条件操作符计算后的最终结果（true 或 false）\n     */\n    private boolean evaluateEventResults(Map<String, Boolean> eventFieldAndWarnResult, String conditionOperator) {\n        // 检查输入是否为 null 或为空\n        if (eventFieldAndWarnResult == null || eventFieldAndWarnResult.isEmpty()) {\n            return false;\n        }\n\n        // 如果只有一个元素，直接返回该元素的值\n        if (eventFieldAndWarnResult.size() == 1) {\n            return eventFieldAndWarnResult.values().iterator().next();\n        }\n\n        // 确定操作符类型\n        RuleCondCombOpEnum opEnum = RuleCondCombOpEnum.fromCode(conditionOperator);\n\n        // 初始化结果，根据操作符类型\n        boolean result;\n        if (opEnum == RuleCondCombOpEnum.AND) {\n            result = true; // 对于 AND，初始值为 true\n            for (Boolean eventResult : eventFieldAndWarnResult.values()) {\n                if (!eventResult) {\n                    return false; // 任何一个 false 都返回 false\n                }\n            }\n        } else if (opEnum == RuleCondCombOpEnum.OR) {\n            result = false; // 对于 OR，初始值为 false\n            for (Boolean eventResult : eventFieldAndWarnResult.values()) {\n                if (eventResult) {\n                    return true; // 任何一个 true 都返回 true\n                }\n            }\n        } else {\n            log.warn(\"因规则[{}]的条件组合操作符非法，故跳过此次计算！\", ruleInfoDTO.getRuleCode());\n            return false;\n        }\n\n        return result;\n    }\n}\n',
        'system', 'system', '2025-02-12 16:43:03', '2025-02-18 18:58:13');

-- ----------------------------
-- Table structure for slr_rule_target
-- ----------------------------
DROP TABLE IF EXISTS `slr_rule_target`;
CREATE TABLE `slr_rule_target`
(
    `id`           bigint UNSIGNED                                        NOT NULL AUTO_INCREMENT COMMENT '自增主键ID',
    `channel`      varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '渠道',
    `target_code`  varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '目标编号',
    `target_field` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '目标字段',
    `target_name`  varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '目标名称',
    `target_desc`  varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '目标描述',
    `creator`      varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '创建用户',
    `updater`      varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin  NULL DEFAULT NULL COMMENT '更新用户',
    `create_time`  datetime                                               NULL DEFAULT NULL COMMENT '创建时间',
    `update_time`  datetime                                               NULL DEFAULT NULL COMMENT '创建时间',
    PRIMARY KEY (`id`) USING BTREE,
    UNIQUE INDEX `uk_target_code` (`target_code` ASC) USING BTREE
) ENGINE = InnoDB
  AUTO_INCREMENT = 8
  CHARACTER SET = utf8mb4
  COLLATE = utf8mb4_bin COMMENT = '风控规则目标表'
  ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of slr_rule_target
